function e(n){return n.map(i=>({id:i.id,...i.data()}))}function a(n){if(typeof n=="object"&&n&&"code"in n){const i=String(n.code);return i.includes("redirect-unavailable")?"Su iPhone apri il link in Safari (non dentro app esterne) e riprova con Google.":i.includes("missing-initial-state")?"Sessione Google non valida su questo browser. Apri il sito in Safari e riprova.":i.includes("permission-denied")?"Non hai i permessi per questa azione.":i.includes("unauthenticated")?"La sessione è scaduta. Accedi di nuovo.":i.includes("invalid-argument")?"Alcuni dati non sono corretti. Controlla e riprova.":i.includes("failed-precondition")?"Manca una configurazione tecnica lato server. Riprova tra poco.":i.includes("internal")?"Qualcosa non ha funzionato. Riprova tra pochi secondi.":"Operazione non completata. Riprova."}if(n instanceof Error){const i=n.message.toLowerCase();return i.includes("token")||i.includes("credential")?"Sessione non valida. Esci e accedi di nuovo.":"Si è verificato un problema. Riprova."}return"Operazione non riuscita."}export{e as m,a as t};
